     5→/**
     6→ * A representation of Python objects of type tuple.
     7→ *
     8→ * @param <InnerType> the type of each element in this tuple
     9→ */
    10→public class PyTupleObj<InnerType extends APyObj> extends AIterablePyObj<InnerType> {
    11→
    12→    /**
    13→     * Constructor for a PyTupleObj; initializes its value to the input.
    14→     *
    15→     * @param value the value of this PyListObj
    16→     */
    17→    public PyTupleObj(List<InnerType> value) {
    18→        this.value = value;
    19→    }
    20→
    21→    /**
    22→     * Builds and returns a string representation of this object that mirrors the Python
    23→     * string representation (i.e., (elem1, elem2, elem3, ...)).
    24→     *
    25→     * @return a string representation of this object
    26→     */
    27→    @Override
    28→    public String toString() {
    29→        StringBuilder repr = new StringBuilder("(");
    30→
    31→        // Add all of the elements
    32→        for (InnerType elem : this.value) {
    33→            repr.append(elem).append(", ");
    34→        }
    35→
    36→        // Remove last ", " if length is greater than 1; otherwise just remove last " "
    37→        if (this.value.size() > 1) {
    38→            repr = new StringBuilder(repr.substring(0, repr.length() - 2));
    39→        } else if (this.value.size() == 1) {
    40→            repr = new StringBuilder(repr.substring(0, repr.length() - 1));
    41→        }
    42→        repr.append(")");
    43→        return repr.toString();
    44→    }
    45→
    46→    /**
    47→     * Compares this to the input object by value; a wrapper around the implementation
    48→     * in the superclass (APyObj) that first checks that obj is a PyTupleObj.
    49→     *
    50→     * @param obj the object to compare against
    51→     * @return true if this is equivalent by value to obj; false otherwise
    52→     */
    53→    @Override
    54→    public boolean equals(Object obj) {
    55→        if (!(obj instanceof PyTupleObj)) {
    56→            return false;
    57→        }
    58→        return super.equals(obj);
    59→    }
    60→}

