package main.rice.test;

import main.rice.obj.APyObj;

import java.util.List;
import java.util.Objects;

/**
 * Represents a single test case consisting of a list of Python object arguments.
 */
public class TestCase {

    private final List<APyObj> args;

    public TestCase(List<APyObj> args) {
        this.args = args;
    }

    public List<APyObj> getArgs() {
        return args;
    }

    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase)) {
            return false;
        }
        TestCase other = (TestCase) obj;
        return this.args.equals(other.args);
    }

    @Override
    public int hashCode() {
        return Objects.hash(args);
    }

    @Override
    public String toString() {
        return args.toString();
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

import java.util.List;
import java.util.Set;

/**
 * Abstract base class for all Python node types.
 * A node represents a domain of possible Python values and can generate them exhaustively or randomly.
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class APyNode<T extends APyObj> {

    protected List<Integer> exDomain;
    protected List<Integer> ranDomain;

    public List<Integer> getExDomain() {
        return exDomain;
    }

    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    public List<Integer> getRanDomain() {
        return ranDomain;
    }

    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    public abstract APyNode<?> getLeftChild();

    public abstract APyNode<?> getRightChild();

    public abstract Set<T> genExVals();

    public abstract T genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * Abstract base class for iterable Python node types (list, set, tuple, dict).
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class AIterablePyNode<T extends APyObj> extends APyNode<T> {

    protected APyNode<?> leftChild;
    protected APyNode<?> rightChild;

    @Override
    public APyNode<?> getLeftChild() {
        return leftChild;
    }

    @Override
    public APyNode<?> getRightChild() {
        return rightChild;
    }
}

