import java.util.Set;

/**
 * Node for generating Python integer values.
 * The exDomain and ranDomain are lists of integer values.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private static final Random RAND = new Random();

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    @Override
    public PyIntObj genRandVal() {
        int idx = RAND.nextInt(ranDomain.size());
        return new PyIntObj(ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
