import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Node for generating Python list values.
 * Lists allow duplicate elements and maintain order.
 * The exDomain/ranDomain represent possible lengths.
 *
 * @param <T> the type of element in the list
 */
public class PyListNode<T extends APyObj> extends AIterablePyNode<PyListObj<T>> {

    private static final Random RAND = new Random();

    @SuppressWarnings("unchecked")
    public PyListNode(APyNode<T> leftChild) {
        this.leftChild = leftChild;
        this.rightChild = null;
    }

    @SuppressWarnings("unchecked")
    private APyNode<T> getTypedLeftChild() {
        return (APyNode<T>) leftChild;
    }

    @Override
    public Set<PyListObj<T>> genExVals() {
        Set<PyListObj<T>> result = new HashSet<>();
        APyNode<T> child = getTypedLeftChild();
        List<T> childVals = new ArrayList<>(child.genExVals());

        for (int len : exDomain) {
            generateWithRepetition(childVals, len, new ArrayList<>(), result);
        }

        return result;
    }

    /**
     * Generates all sequences of the given length from elements (with repetition allowed).
     */
    private void generateWithRepetition(List<T> elements, int length,
                                        List<T> current, Set<PyListObj<T>> result) {
        if (current.size() == length) {
            result.add(new PyListObj<>(new ArrayList<>(current)));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            generateWithRepetition(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyListObj<T> genRandVal() {
        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
        APyNode<T> child = getTypedLeftChild();
        List<T> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(child.genRandVal());
        }
        return new PyListObj<>(elements);
    }
}

