import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Node for generating Python set values.
 * Sets do not allow duplicate elements.
 * The exDomain/ranDomain represent possible sizes.
 *
 * @param <T> the type of element in the set
 */
public class PySetNode<T extends APyObj> extends AIterablePyNode<PySetObj<T>> {

    private static final Random RAND = new Random();

    public PySetNode(APyNode<T> leftChild) {
        this.leftChild = leftChild;
        this.rightChild = null;
    }

    @SuppressWarnings("unchecked")
    private APyNode<T> getTypedLeftChild() {
        return (APyNode<T>) leftChild;
    }

    @Override
    public Set<PySetObj<T>> genExVals() {
        Set<PySetObj<T>> result = new HashSet<>();
        APyNode<T> child = getTypedLeftChild();
        List<T> childVals = new ArrayList<>(child.genExVals());

        for (int size : exDomain) {
            generateCombinations(childVals, size, 0, new ArrayList<>(), result);
        }

        return result;
    }

    /**
     * Generates all combinations of the given size from elements (without repetition).
     */
    private void generateCombinations(List<T> elements, int size, int startIdx,
                                      List<T> current, Set<PySetObj<T>> result) {
        if (current.size() == size) {
            result.add(new PySetObj<>(new HashSet<>(current)));
            return;
        }
        for (int i = startIdx; i < elements.size(); i++) {
            current.add(elements.get(i));
            generateCombinations(elements, size, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PySetObj<T> genRandVal() {
        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
        APyNode<T> child = getTypedLeftChild();
        Set<T> elements = new HashSet<>();
        int maxAttempts = size * 1000 + 100;
        int attempts = 0;
        while (elements.size() < size && attempts < maxAttempts) {
            elements.add(child.genRandVal());
            attempts++;
        }
        return new PySetObj<>(elements);
    }
}

