import main.rice.obj.PyCharObj;
import main.rice.obj.PyStringObj;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Node for generating Python string values.
 * Takes a string of allowed characters in its constructor.
 * The exDomain/ranDomain represent possible lengths.
 */
public class PyStringNode extends APyNode<PyStringObj> {

    private static final Random RAND = new Random();

    private final String allowedChars;

    public PyStringNode(String allowedChars) {
        this.allowedChars = allowedChars;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();
        List<Character> chars = new ArrayList<>();
        for (char c : allowedChars.toCharArray()) {
            chars.add(c);
        }

        for (int len : exDomain) {
            generateStrings(chars, len, new ArrayList<>(), result);
        }

        return result;
    }

    private void generateStrings(List<Character> chars, int length,
                                 List<PyCharObj> current, Set<PyStringObj> result) {
        if (current.size() == length) {
            result.add(new PyStringObj(new ArrayList<>(current)));
            return;
        }
        for (Character c : chars) {
            current.add(new PyCharObj(c));
            generateStrings(chars, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyStringObj genRandVal() {
        int len = ranDomain.get(RAND.nextInt(ranDomain.size()));
        List<PyCharObj> chars = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            char c = allowedChars.charAt(RAND.nextInt(allowedChars.length()));
            chars.add(new PyCharObj(c));
        }
        return new PyStringObj(chars);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Random;
import java.util.Set;

/**
 * Node for generating Python dictionary values.
 * Has both a left child (key generator) and a right child (value generator).
 * The exDomain/ranDomain represent possible sizes (number of key-value pairs).
 *
 * @param <K> the type of dictionary keys
 * @param <V> the type of dictionary values
 */
public class PyDictNode<K extends APyObj, V extends APyObj> extends APyNode<PyDictObj<K, V>> {

    private static final Random RAND = new Random();

    private final APyNode<K> keyNode;
    private final APyNode<V> valNode;

    public PyDictNode(APyNode<K> keyNode, APyNode<V> valNode) {
        this.keyNode = keyNode;
        this.valNode = valNode;
    }

    @Override
    public APyNode<?> getLeftChild() {
        return keyNode;
    }

    @Override
    public APyNode<?> getRightChild() {
        return valNode;
    }

    @Override
    public Set<PyDictObj<K, V>> genExVals() {
        Set<PyDictObj<K, V>> result = new HashSet<>();
        List<K> keyList = new ArrayList<>(keyNode.genExVals());
        List<V> valList = new ArrayList<>(valNode.genExVals());

        for (int size : exDomain) {
            generateDicts(keyList, valList, size, 0, new LinkedHashMap<>(), result);
        }

        return result;
    }

    /**
     * Generates all dictionaries of the given size by choosing `size` distinct keys
     * from keyList (combinations), and assigning all possible values to each key.
     */
    private void generateDicts(List<K> keyList, List<V> valList, int size, int startIdx,
                                Map<K, V> current, Set<PyDictObj<K, V>> result) {
        if (current.size() == size) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }
        for (int i = startIdx; i < keyList.size(); i++) {
            K key = keyList.get(i);
            for (V val : valList) {
                current.put(key, val);
                generateDicts(keyList, valList, size, i + 1, current, result);
                current.remove(key);
            }
        }
    }

    @Override
    public PyDictObj<K, V> genRandVal() {
        int size = ranDomain.get(RAND.nextInt(ranDomain.size()));
        Map<K, V> dict = new LinkedHashMap<>();
        Set<K> usedKeys = new HashSet<>();
        int maxAttempts = size * 1000 + 100;
        int attempts = 0;
        while (dict.size() < size && attempts < maxAttempts) {
            K key = keyNode.genRandVal();
            if (!usedKeys.contains(key)) {
                usedKeys.add(key);
                dict.put(key, valNode.genRandVal());
            }
            attempts++;
        }
        return new PyDictObj<>(dict);
    }
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates test cases by combining values from multiple argument nodes.
 * Supports exhaustive (Cartesian product) and random test generation.
 */
public class BaseSetGenerator {

    private final List<APyNode<?>> nodes;
    private final int numRand;
    private Set<TestCase> currentTests = new HashSet<>();

    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases (Cartesian product of each node's exhaustive values).
     */
    public Set<TestCase> genExTests() {
        // Generate exhaustive values for each node
        List<List<? extends APyObj>> allVals = new ArrayList<>();
        for (APyNode<?> node : nodes) {
            allVals.add(new ArrayList<>(node.genExVals()));
        }

        Set<TestCase> tests = new HashSet<>();
        cartesianProduct(allVals, 0, new ArrayList<>(), tests);

        currentTests = new HashSet<>(tests);
        return tests;
    }

    private void cartesianProduct(List<List<? extends APyObj>> allVals, int idx,
                                  List<APyObj> current, Set<TestCase> result) {
        if (idx == allVals.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }
        for (APyObj val : allVals.get(idx)) {
            current.add(val);
            cartesianProduct(allVals, idx + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates up to numRand random test cases that don't duplicate tests in currentTests.
     */
    public Set<TestCase> genRandTests() {
        Set<TestCase> randTests = new HashSet<>();
        if (numRand == 0) {
            return randTests;
        }

        int maxAttempts = numRand * 1000 + 100;
        int attempts = 0;

        while (randTests.size() < numRand && attempts < maxAttempts) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : nodes) {
                args.add(node.genRandVal());
            }
            TestCase tc = new TestCase(args);
            if (!currentTests.contains(tc) && !randTests.contains(tc)) {
                randTests.add(tc);
            }
            attempts++;
        }

        return randTests;
    }

    /**
     * Generates the full base set: all exhaustive tests + numRand random tests (no duplicates).
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = genExTests();
        Set<TestCase> randTests = genRandTests();

        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(randTests);
        return result;
    }
}
